INSERT INTO lead_interactions (lead_id, interaction_type, message_text, interaction_metadata, created_at)
SELECT id, 'dm', $2, $3, NOW() FROM leads WHERE email = $1;

UPDATE leads
SET lead_score = lead_score + 5,
    lead_stage = CASE WHEN lead_stage = 'new' THEN 'engaged' ELSE lead_stage END
WHERE email = $1;

